using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the default discriminator property from
            // "Discriminator" to "$type". Preserve the old name so existing
            // 500K documents (and raw SQL queries that reference c.Discriminator)
            // keep working without a data migration.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the default id format from "EntityType|Key"
            // to just the raw key value. Preserve the legacy format so
            // existing documents with ids like "Product|123" stay readable.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Opt back in to the legacy "EntityType|Key" id format globally
        // so that lookups against existing documents still work.
        // (Remove this once all documents have been re-written with new ids.)
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

