class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator"
        // as the discriminator property name in OnModelCreating.
        // If we had NOT done that, EF Core 9 would use "$type" and this query
        // would silently return zero results.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 removed sync I/O for the Cosmos provider.
        // ToList() now throws InvalidOperationException; use async.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

