using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE #1 — Discriminator property renamed.
            // EF Core 9 writes "$type" instead of "Discriminator".
            // Existing 500K docs use "Discriminator", and our raw SQL
            // queries filter on c.Discriminator, so we must keep the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE #2 — HasIndex() now throws at model build.
            // It was silently ignored in EF 8. Removed.
            // (Cosmos indexes are managed via indexing policy, not EF.)

            // BREAKING CHANGE #3 — JSON "id" format changed.
            // EF 8 wrote ids as "Product|123"; EF 9 writes just "123".
            // Existing documents cannot be found by key unless we
            // keep the old format. We add an explicit property that
            // maps to the JSON "id" and preserve the legacy format.
            entity.Property(p => p.CosmosId)
                  .ToJsonProperty("id");
        });
    }
}

class Product
{
    // Logical primary key — still the EF key.
    public int Id { get; set; }

    // Explicit Cosmos document id to preserve the legacy "Product|123" format.
    // For new entities, set this in application code or a SaveChanges interceptor:
    //   product.CosmosId = $"Product|{product.Id}";
    public string CosmosId { get; set; } = null!;

    public string Sku { get; set; } = null!;
}

